def download_file(url: str, dst_path: Path, timeout: int = 60) -> Path:
    dst_path.parent.mkdir(parents=True, exist_ok=True)
    with urllib.request.urlopen(url, timeout=timeout) as resp, open(dst_path, "wb") as f:
        shutil.copyfileobj(resp, f)
    return dst_path


def safe_torch_load(source, map_location="cpu"):
    return torch.load(source, map_location=map_location)


def load_checkpoint_from_url(url: str, map_location="cpu"):
    with tempfile.NamedTemporaryFile(suffix=".pt", delete=False) as tmp:
        tmp_path = Path(tmp.name)
    try:
        download_file(url, tmp_path)
        return safe_torch_load(tmp_path, map_location=map_location)
    finally:
        try:
            tmp_path.unlink(missing_ok=True)
        except Exception:
            pass


def is_url(s: str) -> bool:
    try:
        parsed = urllib.parse.urlparse(s)
        return parsed.scheme in ("http", "https")
    except Exception:
        return False


def build_model(arch: str, num_classes: int):
    arch = arch.lower()
    if arch == "resnet18":
        model = models.resnet18(weights=None)
        model.fc = nn.Linear(model.fc.in_features, num_classes)
        return model
    if arch == "resnet34":
        model = models.resnet34(weights=None)
        model.fc = nn.Linear(model.fc.in_features, num_classes)
        return model
    if arch == "resnet50":
        model = models.resnet50(weights=None)
        model.fc = nn.Linear(model.fc.in_features, num_classes)
        return model
    if arch == "mobilenet_v2":
        model = models.mobilenet_v2(weights=None)
        model.classifier[-1] = nn.Linear(model.classifier[-1].in_features, num_classes)
        return model
    if arch == "efficientnet_b0":
        model = models.efficientnet_b0(weights=None)
        model.classifier[-1] = nn.Linear(model.classifier[-1].in_features, num_classes)
        return model
    raise ValueError(f"Unsupported architecture: {arch}")


def infer_state_dict(obj):
    if isinstance(obj, dict):
        for key in ("state_dict", "model_state_dict", "model", "net", "weights"):
            if key in obj and isinstance(obj[key], dict):
                return obj[key]
        if all(isinstance(k, str) for k in obj.keys()):
            return obj
    return obj


def strip_module_prefix(state_dict):
    new_sd = {}
    for k, v in state_dict.items():
        nk = k[7:] if k.startswith("module.") else k
        new_sd[nk] = v
    return new_sd


def load_pretrained_weights(model, checkpoint, strict=False):
    state_dict = infer_state_dict(checkpoint)
    if not isinstance(state_dict, dict):
        raise ValueError("Checkpoint does not contain a state dict.")
    state_dict = strip_module_prefix(state_dict)
    model_state = model.state_dict()
    compatible = {}
    for k, v in state_dict.items():
        if k in model_state and hasattr(v, "shape") and hasattr(model_state[k], "shape"):
            if v.shape == model_state[k].shape:
                compatible[k] = v
    model_state.update(compatible)
    model.load_state_dict(model_state, strict=strict)
    return model


def get_transforms(image_size=224):
    return {
        "train": transforms.Compose(
            [
                transforms.RandomResizedCrop(image_size),
                transforms.RandomHorizontalFlip(),
                transforms.ToTensor(),
                transforms.Normalize([0.485, 0.456, 0.406], [0.229, 0.224, 0.225]),
            ]
        ),
        "val": transforms.Compose(
            [
                transforms.Resize(int(image_size * 1.14)),
                transforms.CenterCrop(image_size),
                transforms.ToTensor(),
                transforms.Normalize([0.485, 0.456, 0.406], [0.229, 0.224, 0.225]),
            ]
        ),
    }


def make_dataloaders(data_dir, batch_size, image_size=224, num_workers=4):
    tfms = get_transforms(image_size)
    train_dir = Path(data_dir) / "train"
    val_dir = Path(data_dir) / "val"
    train_ds = datasets.ImageFolder(str(train_dir), transform=tfms["train"])
    val_ds = datasets.ImageFolder(str(val_dir), transform=tfms["val"])
    train_loader = DataLoader(train_ds, batch_size=batch_size, shuffle=True, num_workers=num_workers, pin_memory=True)
    val_loader = DataLoader(val_ds, batch_size=batch_size, shuffle=False, num_workers=num_workers, pin_memory=True)
    return train_loader, val_loader, len(train_ds.classes)


def train_one_epoch(model, loader, criterion, optimizer, device):
    model.train()
    running_loss = 0.0
    running_correct = 0
    total = 0
    for images, labels in loader:
        images = images.to(device)
        labels = labels.to(device)
        optimizer.zero_grad(set_to_none=True)
        outputs = model(images)
        loss = criterion(outputs, labels)
        loss.backward()
        optimizer.step()
        running_loss += loss.item() * images.size(0)
        preds = outputs.argmax(dim=1)
        running_correct += (preds == labels).sum().item()
        total += labels.size(0)
    return running_loss / max(total, 1), running_correct / max(total, 1)


@torch.no_grad()
def evaluate(model, loader, criterion, device):
    model.eval()
    running_loss = 0.0
    running_correct = 0
    total = 0
    for images, labels in loader:
        images = images.to(device)
        labels = labels.to(device)
        outputs = model(images)
        loss = criterion(outputs, labels)
        running_loss += loss.item() * images.size(0)
        preds = outputs.argmax(dim=1)
        running_correct += (preds == labels).sum().item()
        total += labels.size(0)
    return running_loss / max(total, 1), running_correct / max(total, 1)


def freeze_backbone(model, arch):
    arch = arch.lower()
    if arch.startswith("resnet"):
        for name, param in model.named_parameters():
            param.requires_grad = name.startswith("fc.")
    elif arch == "mobilenet_v2":
        for name, param in model.named_parameters():
            param.requires_grad = name.startswith("classifier.")
    elif arch == "efficientnet_b0":
        for name, param in model.named_parameters():
            param.requires_grad = name.startswith("classifier.")
    return model


def save_checkpoint(path, model, optimizer, epoch, val_acc, arch, num_classes, classes):
    path = Path(path)
    path.parent.mkdir(parents=True, exist_ok=True)
    torch.save(
        {
            "epoch": epoch,
            "val_acc": val_acc,
            "arch": arch,
            "num_classes": num_classes,
            "classes": classes,
            "model_state_dict": model.state_dict(),
            "optimizer_state_dict": optimizer.state_dict(),
        },
        path,
    )


def main():
    parser = argparse.ArgumentParser()
    parser.add_argument("--model-url", type=str, default="", help="URL to a pretrained checkpoint to download.")
    parser.add_argument("--arch", type=str, default="resnet18", help="Model architecture to instantiate.")
